import { Component } from '@angular/core';
import { Observable } from 'rxjs';
import { AuthService } from './core/services/auth.service';
import { Role } from './core/models/index';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss'],
})
export class AppComponent {
  title = 'TallerNova Exportación';
  isAuthenticated$: Observable<boolean>;
  isAdmin$: Observable<boolean>;

  constructor(private readonly authService: AuthService) {
    this.isAuthenticated$ = this.authService.getIsAuthenticated$();
    this.isAdmin$ = this.authService.hasRole$(Role.ADMIN);
  }

  logout(): void {
    this.authService.logout();
  }
}
<div class="app-shell">
  <header class="app-header">
    <div class="header-content">
      <div>
        <h1>{{ title }}</h1>
        <p>Exporta los resultados de conciliación en JSON o CSV.</p>
      </div>
      <nav class="app-nav">
        <a routerLink="/dashboard" routerLinkActive="active" *ngIf="isAuthenticated$ | async">Dashboard</a>
        <a routerLink="/accounts" routerLinkActive="active" *ngIf="isAuthenticated$ | async">Cuentas</a>
        <a routerLink="/incidents" routerLinkActive="active" *ngIf="isAuthenticated$ | async">Incidentes</a>
        <a routerLink="/export" routerLinkActive="active" *ngIf="isAdmin$ | async">Exportar</a>
        <a routerLink="/login" routerLinkActive="active" *ngIf="!(isAuthenticated$ | async)">Login</a>
        <button class="nav-button" *ngIf="isAuthenticated$ | async" (click)="logout()">Logout</button>
      </nav>
    </div>
  </header>

  <main class="app-content">
    <router-outlet></router-outlet>
  </main>
</div>
